                                            {tab === 'paste' ? 'Paste Text' : 'Upload PDF'}
                                        </button>
                                    ))}
                                </div>

                                {inputTab === 'paste' && (
                                    <textarea
                                        placeholder="Paste your questions here — e.g. from a practice test, quiz, or textbook. The AI will extract all multiple-choice questions automatically."
